export const PROJECTS = {
  SetCardGame: {
    title: "Set Card Game",
    description:
      "The Set game developed in Java integrates client-side and server-side components, featuring a user-friendly GUI for intuitive gameplay and robust server logic for managing game state and real-time communication. Utilizing multithreading, the system efficiently handles concurrent player interactions, enhancing scalability and responsiveness in multiplayer sessions.",
    skils: "Skils: Java, Multithreading, GUI",
  },
  ClientServer: {
    title: "Client Server",
    description:
      "This project integrates client-side (C++) and server-side (Java) components to create a versatile interactive system, with the client-side managing user interactions and communication with the server, and the server-side supporting multiple communication models for robust and scalable operations. The server can operate using a Thread-per-Client model for dedicated thread management or the reactor pattern for event-driven scalability, demonstrating proficiency in C++ and Java, and offering flexibility to enhance responsiveness in interactive applications.",
    skils: "Skils: C++, Java, Client-Server Architecture",
  },
  shell: {
    title: "Linux shell",
    description:
      "This project focuses on developing a basic shell in C for Linux, serving as a crucial interface between users and the operating system by executing commands, managing system resources, and supporting advanced features like input/output redirection, background process handling, and piping between commands. Implementing core functionalities such as command parsing, process management, and signal handling, this project showcases proficiency in system-level programming and efficient shell design principles.",
    skils: "Skils: C, Linux",
  },
};
